import{_ as a,o as t,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"84. Shift Allowances","description":"","frontmatter":{"title":"84. Shift Allowances","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/84-shift-allowances.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/84-shift-allowances.md"}'),o={name:"ebas/mental-health/rpn-pen-mho/allowances/84-shift-allowances.md"};function l(h,e,r,i,c,f){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_84-shift-allowances" tabindex="-1">84. Shift Allowances <a class="header-anchor" href="#_84-shift-allowances" aria-label="Permalink to &quot;84. Shift Allowances&quot;">​</a></h1><p>This clause shall not apply to an Employee over the level of RPN5 if they are not undertaking direct clinical work.</p><p><strong>84.1</strong> Definitions: In this clause:</p><p><strong>(a)</strong> Morning shift means any shift that commences between 6:00 p.m. and 6:30 a.m.</p><p><strong>(b)</strong> Afternoon shift means any shift that finishes between 6:00 p.m. and 8:00 a.m.</p><p><strong>(c)</strong> Night shift means any shift that finishes on the day after commencing duty or commences after midnight and before 5:00am.</p><p><strong>(d)</strong> Sunday night shift means a shift worked by a full-time or part-time Employee that commences on Sunday and concludes on Monday.</p><p><strong>84.2</strong> Application Where a shift meets more than one definition as set out in clause 84.1, the Employee will be paid one shift allowance only, with the higher shift allowance where the rates differ.</p><p><strong>84.3</strong> Allowances In addition to any other rates prescribed elsewhere in this Agreement. The Employee will receive the following allowances where an Employee works:</p><p><strong>(a)</strong> A Morning Shift: an amount set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per rostered period of duty;</p><p><strong>(b)</strong> An Afternoon Shift: an amount set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per rostered period of duty;</p><p><strong>(c)</strong> A Night Shift:</p><p><strong>(i)</strong> In the case of a casual Employee, the amount referred to as the Casual Night Shift Allowance in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per period of duty;</p><p><strong>(ii)</strong> In the case of an Employee who is not a casual Employee, the amount referred to as the Night shift until FFPPOA 1 July 2026, the rate at (c)(i) above as set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>; or</p><p><strong>(iii)</strong> In the case of an Employee who is not a casual Employee, the Sunday Night shift rate in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> for a night shift commencing on a Sunday.</p><p><strong>(iv)</strong> In the case of an Employee who is not a casual Employee from FFPPOA 1 July 2026: <strong>(A)</strong> the rate for a Night Shift commencing on a Monday, Tuesday, Wednesday or Thursday as set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> <strong>(B)</strong> the rate for a Night Shift commencing on a Friday or Saturday as set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>; or <strong>(C)</strong> the Sunday Night shift rate in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> for a Night Shift commencing on a Sunday.</p><p>Plain language terms: shift penalty, shift loading, afternoon shift, night shift pay.</p>',17)])])}const p=a(o,[["render",l]]);export{m as __pageData,p as default};
